        ]
      },
      {
        first: 'Bob',
        last: 'Green',
        classes: [
          { subject: 'science of art', grade: '11th' },
          { subject: 'art art art', grade: '10th' }
        ]
      }
    ],
    score: 0.9415585994720459,
    highlights: [
      {
        score: 0.7354040145874023,
        path: 'teachers.classes.subject',
        texts: [
          { value: 'art of ', type: 'text' },
          { value: 'science', type: 'hit' }
        ]
      },
      {
        score: 0.7871346473693848,
        path: 'teachers.classes.subject',
        texts: [
          { value: 'applied ', type: 'text' },
          { value: 'science', type: 'hit' },
          { value: ' and practical ', type: 'text' },
          { value: 'science', type: 'hit' }
        ]
      },
      {
        score: 0.7581484317779541,
        path: 'teachers.classes.subject',
        texts: [ { value: 'science', type: 'hit' } ]
      },
      {
        score: 0.7189631462097168,
        path: 'teachers.classes.subject',
        texts: [
          { value: 'science', type: 'hit' },
          { value: ' of art', type: 'text' }
        ]
      }
    ]
  },
  {
    _id: 1,
    teachers: [
      {
        first: 'Jane',
